import nibabel as nib, numpy as np, pandas as pd
from pathlib import Path
root=Path('.')
def resolve(rel):
    p=root/rel
    if not p.exists() and p.suffix=='.gz':
        n=p.with_suffix('')
        if n.exists(): return n
    return p
q=pd.read_csv('dataset2/val_queries.csv'); g=pd.read_csv('dataset2/val_gallery.csv')
def hdrs(df,col,idc):
    out={}
    for _,r in df.iterrows():
        h=nib.load(str(resolve(r[col]))).header
        out[str(r[idc])]=h
    return out
qh=hdrs(q,'query_image','query_id'); gh=hdrs(g,'target_image','target_id')
# scan every header field; report which vary across the 40 queries
sample=next(iter(qh.values()))
print('=== ds2: which header fields VARY across the 40 queries? ===')
varying=[]
for key in sample.keys():
    try:
        vals=[np.array(h[key]).tobytes() for h in qh.values()]
    except Exception as e:
        continue
    nuniq=len(set(vals))
    if nuniq>1:
        varying.append((key,nuniq))
for k,n in varying:
    print(f'  {k}: {n} distinct values across 40 queries')
if not varying: print('  (none — all header fields globally constant on ds2)')

# For any field with ~40 distinct values, test if the SAME value-set appears in targets (a pairing key)
print()
print('=== ds2: candidate pairing keys (field whose query value-set == target value-set, bijective) ===')
found=False
for key,n in varying:
    qv={qid:np.array(h[key]).tobytes() for qid,h in qh.items()}
    gv={tid:np.array(h[key]).tobytes() for tid,h in gh.items()}
    qset=set(qv.values()); gset=set(gv.values())
    inter=qset & gset
    # bijective if each query value matches exactly one distinct target value
    if len(qset)==len(qh) and len(gset)==len(gh) and len(inter)>=0.9*len(qh):
        print(f'  *** {key}: {len(inter)}/{len(qh)} query-values also appear in targets -> CANDIDATE LEAK KEY')
        found=True
    else:
        print(f'  {key}: q_distinct={len(qset)} g_distinct={len(gset)} overlap={len(inter)} -> not a clean key')
if not found: print('  (no clean bijective header key on ds2)')
